ds = load_dataset('ryanmarten/OpenThoughts-1k-sample')
train = ds['train'] if 'train' in ds else next(iter(ds.values()))

# Identify domain column
domain_col = None
for cand in ['domain','topic','category']:
    if cand in train.column_names:
        domain_col = cand
        break
if domain_col is None:
    raise RuntimeError('Domain column not found: ' + str(train.column_names))

# Identify deepseek-related content field
# Prefer reasoning/trace/thinking; else messages; else text/content
content_field = None
for cand in ['reasoning','trace','thinking']:
    if cand in train.column_names:
        content_field = cand
        break
use_messages = False
if content_field is None and 'messages' in train.column_names:
    use_messages = True
elif content_field is None:
    for cand in ['text','content','prompt','question','input']:
        if cand in train.column_names:
            content_field = cand
            break

# Initialize tokenizer
tokenizer = AutoTokenizer.from_pretrained('Qwen/Qwen2.5-1.5B-Instruct')

# Filter science domain
science_rows = [ex for ex in train if str(ex[domain_col]).strip().lower() == 'science']

# Build text per example
def build_text(ex):
    if content_field is not None:
        return ex.get(content_field, '')
    if use_messages:
        msgs = ex.get('messages', [])
        # Concatenate role: content
        parts = []
        for m in msgs:
            role = m.get('role','')
            content = m.get('content','')
            if isinstance(content, list):
                content = '\n'.join(
                    [c.get('text','') if isinstance(c, dict) else str(c) for c in content]
                )
            parts.append(f"{role}: {content}")
        return '\n'.join(parts)
    # Fallback: concatenate all string fields
    parts = []
    for k,v in ex.items():
        if isinstance(v, str):
            parts.append(v)
    return '\n'.join(parts)

# Token count
total = 0
for ex in science_rows:
    txt = build_text(ex)
    ids = tokenizer(txt, add_special_tokens=False)['input_ids']
    total += len(ids)

with open('/app/answer.txt','w') as f:
    f.write(str(total))
print('Total science tokens:', total)
